import { precacheAndRoute } from 'workbox-precaching';
import { clientsClaim } from 'workbox-core';

// OneSignal Integration
// @ts-ignore
importScripts('https://cdn.onesignal.com/sdks/web/v16/OneSignalSDK.sw.js');

// Precache all assets generated by Vite
precacheAndRoute(self.__WB_MANIFEST || []);

// With registerType: 'autoUpdate', vite-plugin-pwa automatically injects
// self.skipWaiting() so the new SW activates immediately after install.
// clientsClaim() then takes control of all open tabs straight away,
// so users see updated content on next page open without any manual prompt.
clientsClaim();
